css:
/*
🚫商用/二传
小红书@为睡觉而生的懒大王
dc@mmmmi
 * 主题名称: 懒大王*粉色蔷薇
 * 主题版本: V2
/*


/* --- 1. 全局设定与调色盘 --- */
:root {
  /* --- 唯美梦幻调色盘 --- */
  --theme-pink-main: rgba(228, 164, 178, 1);      /* 主粉色，源自玫瑰 */
  --theme-pink-light: rgba(247, 224, 230, 1);     /* 浅粉色，用于边框和点缀 */
  --theme-lace-white: rgba(253, 248, 250, 1);     /* 界面背景色，蕾丝白 */
  --theme-bubble-white: rgba(255, 255, 255, 1);   /* 气泡背景色，纯白 */
  --theme-text-main: rgba(85, 75, 90, 1);         /* 主文字色，柔和的深灰紫 */
  --theme-text-secondary: rgba(150, 140, 155, 1); /* 次要文字色，浅灰紫 */
  --text-shadow-light: rgba(255, 255, 255, 0.7);  /* 文字的白色浅阴影 */

  /* --- 核心插图 --- */
  --char-header-image: url('https://s1.imagehub.cc/images/2025/09/01/078281f7cb217f50cd56d9d0c563a149.png');
  --user-header-image: url('https://s1.imagehub.cc/images/2025/09/01/111cdd1377eb6ac42a9ed96c7957a77a.png');
  --avatar-frame-size: 64px;

  /* --- 交互组件颜色 --- */
  --input-bg-color: rgba(255, 255, 255, 0.8);
  --checked-color: var(--theme-pink-main);
}

/* --- 基础重置与全局字体 --- */
* {
  box-sizing: border-box;
  scrollbar-width: none;
  -ms-overflow-style: none;
}

body,
button,
input,
textarea,
code,
select {
  font-family: 'Noto Serif SC', '思源宋体', serif !important;
}

body {
  background: var(--theme-lace-white) !important;
  color: var(--theme-text-main) !important;
}

::-webkit-scrollbar {
  display: none;
  width: 0;
  height: 0;
}

/* --- 状态重置 --- */
*:disabled,
*[disabled],
[aria-disabled="true"],
[readonly],
.disabled,
.inactive,
.disabled *,
.inactive * {
  color: inherit !important;
  -webkit-text-fill-color: inherit !important;
  text-fill-color: inherit !important;
  opacity: 1 !important;
  filter: none !important;
}

svg,
img {
  opacity: 1 !important;
  filter: none !important;
}


/* --- 2. 聊天区域 --- */

/* 消息容器 */
.mes {
  display: flex !important;
  flex-direction: column;
  align-items: center;
  max-width: 95%;
  margin: 80px auto 0 auto !important;
  padding: 0 5px 15px !important;
  position: relative;
  background: transparent !important;
}

/* 气泡主体 */
.mes .mes_block {
  position: relative;
  overflow: hidden !important;
  padding: 15px 15px 40px 15px;
  margin-top: 25px !important;
  border-radius: 12px;
  background: var(--theme-bubble-white) !important;
  box-shadow: 0 4px 20px rgba(180, 160, 170, 0.25);
  transition: all 0.3s ease;
  z-index: 1;
  border: 2px dashed var(--theme-pink-main);
  outline: 1px dashed var(--theme-pink-main);
  outline-offset: 4px;
}

/* 气泡顶部插图 (伪元素) */
.mes .mes_block::before {
  content: "";
  display: block;
  width: calc(100% + 30px);
  margin: -15px -15px 15px -15px;
  background-size: cover;
  background-position: center center;
  background-repeat: no-repeat;
}

.mes[is_user='false'] .mes_block::before {
  background-image: var(--char-header-image);
  padding-top: 67.38%; /* 1120/1662 */
}

.mes[is_user='true'] .mes_block::before {
  background-image: var(--user-header-image);
  padding-top: 45.14%; /* 749/1659 */
}

/* 消息文本 */
.mes .mes_text {
  padding: 0 !important;
  text-shadow: 0.5px 0.5px 5px var(--text-shadow-light);
  position: relative;
  z-index: 2;
  text-align: justify;
  color: var(--theme-text-main);
}

.mes .mes_name {
  display: none !important;
}

/* 下划线 */
.mes_text u {
  color: var(--theme-pink-main) !important;
  border-bottom: 1.5px solid var(--theme-pink-main);
  text-decoration: none;
  padding-bottom: 1px;
  background: transparent !important;
}


/* --- 3. 头像与装饰 --- */

/* 头像容器 */
.mesAvatarWrapper {
  position: absolute !important;
  top: -60px !important;
  left: 50% !important;
  transform: translateX(-50%);
  width: auto !important;
  margin: 0 !important;
  text-align: center;
  z-index: 3;
  pointer-events: none !important;
}

.mesAvatarWrapper .avatar {
  position: relative;
  width: var(--avatar-frame-size) !important;
  height: var(--avatar-frame-size) !important;
  margin: 0 auto 25px !important;
  z-index: 1;
}

.mes .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  border-radius: 50%;
  border: 2px solid rgba(255, 255, 255, 0.8);
  box-shadow: 0 0 0 2px var(--theme-pink-main), 0 2px 10px rgba(228, 164, 178, 0.3), inset 0 0 10px rgba(255, 255, 255, 0.5);
  transition: all 0.3s ease;
  filter: brightness(1.05) contrast(1.1);
}

/* 头像装饰贴图 (伪元素) */
.mesAvatarWrapper .avatar::after {
  content: '';
  position: absolute;
  width: 120%;
  height: 120%;
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/2d0d5283b1be8fdd3146f957c4bd5b7a.png');
  background-size: contain;
  background-repeat: no-repeat;
  pointer-events: none;
  z-index: 2;
}

.mes[is_user='false'] .mesAvatarWrapper .avatar::after {
  top: -15%;
  left: -15%;
}

.mes[is_user='true'] .mesAvatarWrapper .avatar::after {
  bottom: -15%;
  right: -15%;
  transform: rotate(180deg);
}


/* --- 4. 消息信息栏与编辑按钮 --- */

/* 信息栏容器 */
.mes_info_bar {
  position: absolute !important;
  top: 10px !important;
  left: 50% !important;
  transform: translateX(-50%) !important;
  display: inline-block !important;
  white-space: nowrap;
  z-index: 4;
  background: transparent !important;
  border: none !important;
  padding: 0 !important;
}

/* 信息栏项目 (时间戳、ID等) */
.name_text,
.timestamp,
.mesIDDisplay,
.mes_timer,
.tokenCounterDisplay {
  display: inline-block !important;
  margin: 0 4px !important;
  color: var(--theme-text-secondary) !important;
  background: rgba(255, 255, 255, 0.6) !important;
  border: 1px solid var(--theme-pink-light) !important;
  border-radius: 10px !important;
  padding: 3px 10px !important;
  backdrop-filter: blur(2px);
  font-size: 0.75em !important;
  opacity: 1 !important;
  transition: all 0.3s ease;
}

/* 单独美化名字 */
.name_text {
  color: var(--theme-text-main) !important;
  font-weight: bold !important;
  font-size: 1em !important;
  border: none !important;
  background: transparent !important;
  backdrop-filter: none !important;
  padding: 3px 5px !important;
}

/* 信息栏项目悬停效果 */
.name_text:hover,
.timestamp:hover,
.mesIDDisplay:hover,
.mes_timer:hover,
.tokenCounterDisplay:hover {
  background: rgba(255, 255, 255, 0.9) !important;
  color: var(--theme-text-main) !important;
  box-shadow: 0 0 5px var(--theme-pink-main);
}

/* 消息编辑按钮 */
.mes_edit_buttons button {
  background: rgba(255, 255, 255, 0.5) !important;
  border: 1px solid var(--theme-pink-light) !important;
  padding: 0 !important;
  margin: 0 !important;
  width: 32px !important;
  height: 32px !important;
  border-radius: 50% !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  transition: all 0.2s ease-in-out !important;
}

.mes_edit_buttons button i {
  color: var(--theme-text-secondary) !important;
  font-size: 14px !important;
  line-height: 1 !important;
}

.mes_edit_buttons button:hover {
  background: var(--theme-pink-main) !important;
  border-color: var(--theme-pink-main) !important;
  transform: translateY(-2px);
  filter: drop-shadow(0 3px 5px rgba(228, 164, 178, 0.4));
}

.mes_edit_buttons button:hover i {
  color: white !important;
}

.mes_edit_buttons button:active {
  transform: translateY(0px) scale(0.95);
  filter: drop-shadow(0 1px 2px rgba(228, 164, 178, 0.5));
}


/* --- 5. 思维链 (Thinking...) --- */
.mes_reasoning_header {
  background: transparent !important;
  border: none !important;
  color: transparent !important;
  box-shadow: none !important;
  display: block !important;
  width: 80%;
  max-width: 400px;
  height: 35px;
  margin: 25px auto !important;
  position: relative;
  cursor: pointer;
  user-select: none;
}

.mes_reasoning_header::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(90deg, rgba(247, 224, 230, 0.6), rgba(228, 164, 178, 0.7), rgba(247, 224, 230, 0.6));
  border-radius: 20px;
  opacity: 0.8;
  transition: all 0.3s ease;
  z-index: 1;
}

.mes_reasoning_header::after {
  content: '-—💫. ⭐. 🌟. ✨. ⚡. 🌙—-';
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 100%;
  text-align: center;
  color: white !important;
  font-size: 1.1em !important;
  font-weight: normal !important;
  text-shadow: 0 0 5px rgba(0, 0, 0, 0.3), 0 0 8px var(--theme-pink-main);
  z-index: 2;
  transition: all 0.3s ease;
}

.mes_reasoning_header:hover::before {
  opacity: 1;
  box-shadow: 0 0 15px var(--theme-pink-main);
}

.mes_reasoning_header:hover::after {
  text-shadow: 0 0 8px white, 0 0 15px var(--theme-pink-main);
  letter-spacing: 1px;
}


/* --- 6. 顶部与底部栏 --- */

/* 顶部栏与发送栏背景 */
body.no-blur #top-bar,
body.no-blur #send_form {
  background-color: var(--theme-lace-white) !important;
}

/* 发送栏容器 */
#send_form {
  align-items: center !important;
  width: calc(100% - 20px) !important;
  margin: 0 auto 10px auto !important;
  padding: 5px 10px !important;
  border: 2px solid var(--theme-pink-light) !important;
  border-radius: 12px !important;
  min-height: auto !important;
  background: rgba(255, 255, 255, 0.7);
  backdrop-filter: blur(4px);
}

/* 发送输入框 */
#send_textarea {
  background: transparent !important;
  color: var(--theme-text-main) !important;
  border: none !important;
  box-shadow: none !important;
}

#send_textarea::placeholder {
  color: var(--theme-text-secondary) !important;
  opacity: 0.7;
}

/* 顶部导航栏图标容器 */
#top-settings-holder .drawer-icon {
  font-size: 0 !important;
  color: transparent !important;
  width: 32px !important;
  height: 32px !important;
  background-size: contain !important;
  background-position: center !important;
  background-repeat: no-repeat !important;
  margin: 0 2px !important;
}

#top-settings-holder .drawer-icon::before {
  content: none !important;
}

/* 顶部导航栏图标 (交替使用两张图片) */
#leftNavDrawerIcon,
#advanced-formatting-button .drawer-icon,
#user-settings-button .drawer-icon,
#extensions-settings-button .drawer-icon,
#persona-management-button .drawer-icon {
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/d935ad2e61a32df1fa33afb32ff8025d.png') !important;
}

#sys-settings-button .drawer-icon,
#WI-SP-button .drawer-icon,
#table_drawer_icon.drawer-icon,
#logo_block .drawer-icon,
#rightNavDrawerIcon {
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/fb70b40a49b2ab4938c55794cda6eaf7.png') !important;
}

/* 底部栏按钮 (发送/停止) */
#send_but,
#stscript_stop.active {
  background: url('https://s1.imagehub.cc/images/2025/09/01/8d2f99c333b7ef9e1610a1414da71af8.png') center/contain no-repeat !important;
  font-size: 0 !important;
  color: transparent !important;
  width: 42px !important;
  height: 42px !important;
  border: none !important;
  padding: 0 !important;
  margin: 0 0 0 5px !important;
  transition: transform 0.2s ease !important;
  cursor: pointer;
}

#send_but::before,
#stscript_stop.active::before {
  content: none !important;
}

#send_but:hover,
#stscript_stop.active:hover {
  transform: translateY(-2px) scale(1.05);
  filter: drop-shadow(0 3px 5px rgba(228, 164, 178, 0.4));
}

#send_but:active,
#stscript_stop.active:active {
  transform: translateY(0px) scale(0.95);
}

/* 底部栏其他图标 (菜单/扩展) */
#leftSendForm .fa-bars,
#extensionsMenuButton {
  font-size: 0 !important;
  color: transparent !important;
  width: 32px !important;
  height: 32px !important;
  background-size: contain !important;
  background-position: center !important;
  background-repeat: no-repeat !important;
}

#leftSendForm .fa-bars::before,
#extensionsMenuButton::before {
  content: none !important;
}

#leftSendForm .fa-bars {
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/d935ad2e61a32df1fa33afb32ff8025d.png') !important;
}

#extensionsMenuButton {
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/fb70b40a49b2ab4938c55794cda6eaf7.png') !important;
}


/* --- 7. 设置面板与抽屉 --- */

/* 抽屉主容器 */
.drawer-content {
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/05e745c412d1a08202957f5c1cf164d3.png') !important;
  background-size: cover !important;
  background-position: center !important;
  background-color: rgba(253, 248, 250, 0.4) !important;
  border: 1px solid var(--theme-pink-light) !important;
  border-radius: 16px !important;
  padding: 10px !important;
}

/* 面板内标题栏 */
:is(.sub_block_title, .inline-drawer-header, #user-settings-block h4, .standoutHeader, #llm_settings_block .inline-drawer-header, #extensions_settings .inline-drawer-toggle.inline-drawer-header, #extensions_settings2 .inline-drawer-toggle.inline-drawer-header) {
  background: var(--theme-pink-main) !important;
  border: 2px dashed var(--theme-pink-main) !important;
  box-shadow: inset 0 0 0 2px var(--theme-lace-white) !important;
  color: white !important;
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.2);
  padding: 5px 15px 5px 45px !important;
  margin: 8px 0 !important;
  width: 100% !important;
  border-radius: 10px !important;
  position: relative !important;
}

/* 标题栏左侧花朵装饰 */
:is(.sub_block_title, .inline-drawer-header, #user-settings-block h4, .standoutHeader, #llm_settings_block .inline-drawer-header, #extensions_settings .inline-drawer-toggle.inline-drawer-header, #extensions_settings2 .inline-drawer-toggle.inline-drawer-header)::before {
  content: '' !important;
  display: block !important;
  position: absolute !important;
  left: 10px !important;
  top: 50% !important;
  transform: translateY(-50%) !important;
  width: 30px !important;
  height: 30px !important;
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/ec646836b4e2f485ea29ada34750b900.png') !important;
  background-size: contain !important;
  background-repeat: no-repeat !important;
  opacity: 0.9;
}

/* 折叠小箭头 */
.inline-drawer-icon {
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/ec646836b4e2f485ea29ada34750b900.png') !important;
  background-size: contain !important;
  background-repeat: no-repeat !important;
  background-position: center !important;
  font-size: 0 !important;
  color: transparent !important;
  width: 22px !important;
  height: 22px !important;
  margin-right: 8px !important;
  transition: transform 0.3s ease !important;
  opacity: 0.8;
}

.inline-drawer-toggle.open .inline-drawer-icon {
  transform: rotate(90deg) !important;
  opacity: 1;
}


/* --- 8. 表单控件 (输入框、滑块等) --- */

/* 文本输入框 */
textarea,
input[type="text"],
input[type="number"] {
  background-color: var(--input-bg-color) !important;
  border: 1px solid var(--theme-pink-light) !important;
  border-radius: 6px !important;
  padding: 8px !important;
  color: var(--theme-text-main) !important;
  transition: all 0.2s ease-in-out;
}

/* 下拉选择框 */
select {
  -webkit-appearance: none;
  -moz-appearance: none;
  appearance: none;
  background-color: var(--input-bg-color) !important;
  background-image: none !important;
  border: 1px solid var(--theme-pink-light) !important;
  border-radius: 6px !important;
  padding-right: 30px !important;
  color: var(--theme-text-main) !important;
}

/* 输入框与下拉框聚焦效果 */
textarea:focus,
input[type="text"]:focus,
input[type="number"]:focus,
select:focus {
  border-color: var(--theme-pink-main) !important;
  box-shadow: 0 0 8px rgba(228, 164, 178, 0.8) !important;
}

/* 滑块 (Slider) */
input[type="range"] {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 20px;
  background: transparent;
  outline: none;
}

input[type="range"]::-webkit-slider-runnable-track {
  width: 100%;
  height: 5px;
  background: var(--theme-pink-light);
  border-radius: 5px;
  cursor: pointer;
}

input[type="range"]::-moz-range-track {
  width: 100%;
  height: 5px;
  background: var(--theme-pink-light);
  border-radius: 5px;
  cursor: pointer;
}

input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  margin-top: -18px;
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/8d2f99c333b7ef9e1610a1414da71af8.png');
  background-size: contain;
  background-repeat: no-repeat;
  background-color: transparent;
  width: 42px;
  height: 42px;
  border: none;
  cursor: pointer;
  transition: transform 0.2s ease;
}

input[type="range"]::-moz-range-thumb {
  background-image: url('https://s1.imagehub.cc/images/2025/09/01/8d2f99c333b7ef9e1610a1414da71af8.png');
  background-size: contain;
  background-repeat: no-repeat;
  background-color: transparent;
  width: 42px;
  height: 42px;
  border: none;
  cursor: pointer;
  transition: transform 0.2s ease;
}

input[type="range"]:hover::-webkit-slider-thumb,
input[type="range"]:hover::-moz-range-thumb {
  transform: scale(1.1);
}

input[type="range"]:active::-webkit-slider-thumb,
input[type="range"]:active::-moz-range-thumb {
  transform: scale(1.05);
}

/* 复选框 (Checkbox) */
input[type="checkbox"] {
  -webkit-appearance: none !important;
  appearance: none !important;
  width: 14px !important;
  height: 14px !important;
  margin: 3px 0 !important;
  border-radius: 50% !important;
  border: 2px dashed var(--theme-pink-main) !important;
  background-color: rgba(255, 255, 255, 0.8) !important;
  position: relative !important;
  vertical-align: -3px !important;
  cursor: pointer !important;
  transition: all 0.2s ease-in-out !important;
}

input[type="checkbox"]:checked {
  border-style: solid !important;
}

input[type="checkbox"]:checked::after {
  content: '' !important;
  position: absolute !important;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-image: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 10 10'%3e%3cpolyline points='2,5 4,7 8,3' stroke='%23E4A4B2' stroke-width='2' fill='none' stroke-linecap='round' stroke-linejoin='round'/%3e%3c/svg%3e") !important;
  background-size: 85% !important;
  background-position: center !important;
  background-repeat: no-repeat !important;
}

/* 选中的头像 */
.avatar-container.selected {
  outline: 2px solid var(--theme-pink-main) !important;
  outline-offset: 2px !important;
  box-shadow: 0 0 15px var(--theme-pink-main) !important;
  background-color: var(--input-bg-color) !important;
}


/* --- 9. 通用交互动画 --- */

/* 基础过渡 */
button,
select,
input[type="checkbox"],
.drawer-icon,
.inline-drawer-icon,
#send_but,
.swipe_left,
.swipe_right {
  transition: all 0.2s ease-in-out !important;
}

/* 悬停效果: 上浮 + 光晕 */
button:hover,
select:hover,
input[type="checkbox"]:hover,
.drawer-icon:hover,
.inline-drawer-icon:hover,
#send_but:hover,
.swipe_left:hover,
.swipe_right:hover {
  transform: translateY(-2px);
  filter: drop-shadow(0 3px 5px rgba(228, 164, 178, 0.4));
}

/* 点击效果: 按下 */
button:active,
select:active,
input[type="checkbox"]:active,
.drawer-icon:active,
.inline-drawer-icon:active,
#send_but:active,
.swipe_left:active,
.swipe_right:active {
  transform: translateY(0px) scale(0.95);
  filter: drop-shadow(0 1px 2px rgba(228, 164, 178, 0.5));
}


/* --- 10. 预设面板 --- */

/* 列表背景 */
#completion_prompt_manager,
#completion_prompt_manager #completion_prompt_manager_list {
  background-color: transparent !important;
}

/* 预设条目 */
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
  background: #fff !important;
  border: 1px dashed var(--theme-pink-light) !important;
  border-radius: 10px !important;
  margin-bottom: 8px !important;
  padding: 10px 15px !important;
  box-shadow: 0 2px 5px rgba(180, 160, 170, 0.1);
  transition: all 0.2s ease !important;
}

/* 悬停与选中状态 */
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt:hover,
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt.selected {
  border-style: solid !important;
  border-color: var(--theme-pink-main) !important;
  background-color: var(--theme-pink-light) !important;
  transform: translateY(-2px);
  box-shadow: 0 4px 8px rgba(180, 160, 170, 0.2);
}

/* 禁用状态 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled {
  background-color: rgba(253, 248, 250, 0.6) !important;
  border-color: rgba(228, 164, 178, 0.4) !important;
  box-shadow: none !important;
  transform: none !important;
}

/* 条目内文字颜色 */
#completion_prompt_manager .completion_prompt_manager_prompt_name,
#completion_prompt_manager .completion_prompt_manager_prompt_name * {
  color: var(--theme-text-main) !important;
  -webkit-text-fill-color: var(--theme-text-main) !important;
}

#completion_prompt_manager .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name,
#completion_prompt_manager .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name * {
  color: var(--theme-text-secondary) !important;
  -webkit-text-fill-color: var(--theme-text-secondary) !important;
}

/* 右侧操作按钮 */
#completion_prompt_manager .completion_prompt_manager_prompt_actions .fa-solid {
  all: unset !important;
  font-family: "Font Awesome 6 Free" !important;
  font-weight: 900 !important;
  display: inline-flex !important;
  align-items: center;
  justify-content: center;
  width: 28px !important;
  height: 28px !important;
  background-color: rgba(255, 255, 255, 0.5) !important;
  border: 1px solid var(--theme-pink-light) !important;
  border-radius: 50% !important;
  color: var(--theme-text-secondary) !important;
  cursor: pointer !important;
  transition: all 0.2s ease !important;
}

#completion_prompt_manager .completion_prompt_manager_prompt_actions .fa-solid:hover {
  color: white !important;
  -webkit-text-fill-color: white !important;
  background-color: var(--theme-pink-main) !important;
  border-color: var(--theme-pink-main) !important;
  transform: scale(1.1) rotate(10deg);
}


/* --- 11. 其他与修复 --- */

/* 翻页箭头 */
.swipe_left,
.swipe_right {
  background: var(--theme-pink-light) !important;
  border: none !important;
  color: var(--theme-pink-main) !important;
  opacity: 0.7 !important;
  width: 30px !important;
  height: 40px !important;
  position: absolute;
  bottom: 15px !important;
  z-index: 5;
  transition: all 0.2s ease;
  border-radius: 8px;
  font-size: 1.5em;
  display: flex;
  align-items: center;
  justify-content: center;
}

.swipe_left:hover,
.swipe_right:hover {
  opacity: 1 !important;
  transform: scale(1.05);
  background: var(--theme-pink-main) !important;
  color: white !important;
}

.swipe_left {
  left: 15px;
}

.swipe_right {
  right: 15px;
}

/* 快速回复栏 */
#send_form:hover #qr--bar {
  height: 35px;
  transition: all 0.5s ease;
}

#qr--bar {
  height: 0.5px;
}

/* 角色头像可点击 */
.mes[is_user="false"] .mesAvatarWrapper {
  pointer-events: auto !important;
  cursor: pointer !important;
  z-index: 100 !important;
}

.mes[is_user="false"] .mesAvatarWrapper:active .avatar img {
  transform: scale(0.95);
  filter: brightness(0.9);
}

/* 隐藏第一条消息的置顶按钮 */
#chat > .mes:first-child .mes_pin_checkbox {
  display: none !important;
}

/* 修复：AI生成内容中的交互按钮无法点击 */
.mes_text button,
.mes_text .interactable {
  position: relative;
  z-index: 5;
  pointer-events: auto !important;
}
